const response = require('cfn-response');
exports.handler = async (event, context) => {
    console.log('Event: ' + JSON.stringify(event));
    try {
        const firstNumber = parseFloat(event.ResourceProperties.FirstNumber);
        const secondNumber = parseFloat(event.ResourceProperties.SecondNumber);
        const operator = event.ResourceProperties.Operator;
        const forceFail = event.ResourceProperties.ForceFail === 'true';

        if (forceFail) {
            throw new Error('Forced failure for testing');
        }

        let result;
        switch(operator) {
            case 'add':
                result = firstNumber + secondNumber;
                break;
            case 'subtract':
                result = firstNumber - secondNumber;
                break;
            case 'multiply':
                result = firstNumber * secondNumber;
                break;
            case 'divide':
                if (secondNumber === 0) throw new Error('Division by zero');
                result = firstNumber / secondNumber;
                break;
            default:
                throw new Error('Invalid operator');
        }

        const responseData = {
            Result: result.toString(),
            Operation: `${firstNumber} ${operator} ${secondNumber} = ${result}`
        };

        await response.send(event, context, response.SUCCESS, responseData);
        return responseData;
    } catch (err) {
        console.error(err);
        await response.send(event, context, response.FAILED, { Error: err.message });
        throw err;
    }
};
